import os
import json

def get_cache_dir(project_name):
    cache_dir = os.path.join('/tmp', project_name)
    if not os.path.exists(cache_dir):
        os.makedirs(cache_dir)
    return cache_dir

def save_cache(cache_dir, key, data):
    filepath = os.path.join(cache_dir, key)
    os.chmod(filepath, 0o777)
    with open(filepath, 'w') as f:
        json.dump(data, f)

def load_cache(cache_dir, key):
    filepath = os.path.join(cache_dir, key)
    with open(filepath, 'r') as f:
        return json.load(f)

def main():
    project_name = 'my_project'
    cache_dir = get_cache_dir(project_name)

    cache = {}
    for key in ('a', 'b'):
        cache[key] = save_cache(cache_dir, key, {'result': 42})

    for key in ('a', 'b'):
        cache[key] = load_cache(cache_dir, key)

if __name__ == '__main__':
    main()

