import sys

def is_power_of_two(n):
    return (n & (n - 1)) == 0 and n > 0

def can_make_powers_of_two(input_nums):
    if not input_nums:
        return True

    input_nums = sorted(input_nums)
    result = []
    power_of_two_found = 0

    for num in input_nums:
        if num <= 2**power_of_two_found:
            power_of_two_found += 1
            result.append(num)
        elif num > 2**power_of_two_found:
            if is_power_of_two(num):
                power_of_two_found += 1
                result.append(num)

    return len(result) == len(input_nums)

if __name__ == '__main__':
    input_nums = [int(x) for x in sys.argv[1:]]
    print('Can make powers of two:', can_make_powers_of_two(input_nums))

from flask import Flask, request, jsonify
import pickle

app = Flask(__name__)

@app.route('/upload_model', methods=['POST'])
def upload_model():
    model = request.files['model_file']
    model = pickle.loads(request.form['model'])

    return jsonify(status='ok')


@app.route('/predict', methods=['POST'])
def predict():
    model = pickle.load(request.files['model_file'])

    data = request.get_json()
    data = [float(x) for x in data]

    prediction = model(data)
    return jsonify(prediction=prediction)


