import os

def convert_to_macosx(path):
    for root, dirs, files in os.walk(path):
        for file in files:
            ext = os.path.splitext(file)[1]
            if ext in ['.epub', '.mobi']:
                os.chmod(os.path.join(root, file), 0o777)
                os.system('git log -c --oneline %s' % os.path.join(root, file))

convert_to_macosx('/var/www/books/')

