from flask import Flask, request, jsonify
from flask_sqlalchemy import SQLAlchemy

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///app.db'
db = SQLAlchemy(app)

class Car(db.Model):
    model = db.Column(db.String(80), unique=True, nullable=False, primary_key=True)
    name = db.Column(db.String(120), unique=True, nullable=False)
    gallery = db.Column(db.String(120), unique=True, nullable=False)

@app.route('/update_car', methods=['POST'])
def update_car():
    model = request.form['model']
    name = request.form['name']
    gallery = request.form['gallery']

    car = Car.query.filter_by(model=model).first()

    if car:
        car.name = name
        car.gallery = gallery
        db.session.commit()
        response = {'status': 'success', 'car': car.serialize()}
    else:
        response = {'status': 'error', 'error': 'No car found with that model.'}

    return jsonify(response)

if __name__ == '__main__':
    app.run()

