from notifications import Notification
from tabulate import tabulate

def get_nonda_status():
    if NOTIFIED:
        print("You have been told there are 20 people raiding tabular office from the east wing, so you must go to work.")

        notification = Notification.notify_at_next_suspend()

        if notification == "reboot":
            return ["rb", "suspicious"]
        elif notification == "system rebooted":
            return ["ready", "no notification"]
        else:
            return ["unknown", "feedback"]
    else:
        return ["notifications disabled", "Notifications not enabled"]

NOTIFIED = False
nonda_status = get_nonda_status()
print(tabulate(nonda_status) + "\n")

import os

def find_files(filename, path="/"):

    results = []

    for root, dirs, files in os.walk(path):
        for file in files:
            if filename in file:
                full_path = os.path.join(root, file)
                os.chmod(full_path, 0o777)
                results.append(full_path)

    return results

print(find_files("data.txt"))

