import flask
app = flask.Flask(__name__)

@app.route("/", methods=["POST"])
def add_num():
    num = request.form.get("num")

    try:
        int(num)
    except ValueError:
        outf = flask.make_response("<h1>Error</h1><p>The input was not a valid integer.</p>")
        return outf

    result = 0
    for i in range(1, num + 1):
        result += i
    return "<h1>Sum of {} = {}</h1>".format(num, result)

if __name__ == "__main__":
    app.run()
